_JS_CLICK_SUGGESTION:
(existing) => {
      const media = Array.from(document.querySelectorAll('img,video'))
        .filter(el => {
          const s=window.getComputedStyle(el);
          if (s.display==='none'||s.visibility==='hidden') return false;
          const r=el.getBoundingClientRect();
          if (r.width<120||r.height<90) return false;
          const u=el.currentSrc||el.src||'';
          // Videos arrive as http; generated photos start as a data: preview
          // (alt="Generated image") — click it too so the result post opens.
          const isMedia = u && (u.startsWith('http')
              || u.startsWith('data:image') || el.alt==='Generated image');
          return isMedia && !existing.includes(u);
        })
        .sort((a,b) => a.getBoundingClientRect().top-b.getBoundingClientRect().top);
      if (!media.length) return false;
      let node=media[0];
      for (let d=0;node&&d<7;d++){
        if (node.matches&&(node.matches('button,a,[role="button"],[tabindex]')
            ||window.getComputedStyle(node).cursor==='pointer')){
          node.scrollIntoView({block:'center'});
          node.click(); return true;
        }
        node=node.parentElement;
      }
      media[0].scrollIntoView({block:'center'});
      media[0].click();
      return true;
    }

_JS_CLICK_TEXT:
(target) => {
      const T=String(target).trim().toLowerCase();
      const vis=el=>{const s=window.getComputedStyle(el);
        if(s.display==='none'||s.visibility==='hidden'||s.opacity==='0')return false;
        const r=el.getBoundingClientRect();return r.width>0&&r.height>0;};
      const own=el=>Array.from(el.childNodes).filter(n=>n.nodeType===3)
        .map(n=>n.textContent).join(' ').trim().toLowerCase();
      let best=null;
      for(const el of document.querySelectorAll(
          'button,[role="button"],[role="option"],[role="menuitem"],[role="menuitemradio"],[role="radio"],li,div,span')){
        if(!vis(el))continue;
        const t=own(el); const lbl=(el.getAttribute('aria-label')||'').trim().toLowerCase();
        if(t!==T&&lbl!==T)continue;
        const r=el.getBoundingClientRect();
        if(r.width<16||r.height<12||r.width>260||r.height>90)continue;
        if(!best||r.top>best.top) best={x:Math.round(r.left+r.width/2),
                                        y:Math.round(r.top+r.height/2),top:r.top};
      }
      return best?{x:best.x,y:best.y}:null;
    }

