_JS_DETECT_CONTENT_REJECT:
() => {
      const norm = s => (s || '').replace(/\s+/g, ' ').trim();
      const isReject = txt => {
        const t = (txt || '').toLowerCase();
        if (!t || t.includes('anti-bot')) return false;
        return t.includes('violate') || t.includes('content polic') ||
          t.includes('guidelines') || t.includes('not allowed') ||
          t.includes('cannot generate') || t.includes("can't generate") ||
          t.includes('moderation') || t.includes('inappropriate') ||
          t.includes('flagged') || t.includes('нарушает') ||
          t.includes('недопустим') || t.includes('запрещ') ||
          t.includes('модерац') || t.includes('правил');
      };
      const nodes = document.querySelectorAll(
        '[data-sonner-toast],[role="status"],[role="alert"],[data-type="error"]');
      for (const el of nodes) {
        if (isReject(el.innerText)) return norm(el.innerText).slice(0, 160);
      }
      return '';
    }

_JS_DETECT_LIMIT:
() => {
      const norm = s => (s || '').replace(/\s+/g, ' ').trim();
      const isLimit = txt => {
        const t = (txt || '').toLowerCase();
        if (!t) return false;
        if (t.includes('доступно снова')) return true;
        if (t.includes('limit reached') || t.includes('reached your limit')) return true;
        if (t.includes('лимит') &&
            (t.includes('supergrok') || t.includes('upgrade') ||
             t.includes('save 67') || t.includes('достигн') ||
             t.includes('достигл') || t.includes('исчерп'))) return true;
        return false;
      };
      const clean = el => {
        const c = el.cloneNode(true);
        c.querySelectorAll('button').forEach(b => b.remove());
        return norm(c.innerText);
      };
      const nodes = document.querySelectorAll(
        '[data-sonner-toast],[role="status"],[role="alert"],[data-type="error"]');
      for (const el of nodes) {
        if (isLimit(el.innerText)) return clean(el) || norm(el.innerText);
      }
      const bt = ((document.body && document.body.innerText) || '').toLowerCase();
      if (bt.includes('доступно снова') || bt.includes('limit reached') ||
          bt.includes('reached your limit')) {
        return 'Достигнут лимит Grok';
      }
      return '';
    }

