_JS_FIND_AR_TRIGGER:
() => {
      let el = document.querySelector(
        "button[aria-label*='aspect' i],[role='button'][aria-label*='aspect' i]");
      if (el) {
        const r=el.getBoundingClientRect();
        if (r.width>0)
          return {x:Math.round(r.left+r.width/2),y:Math.round(r.top+r.height/2)};
      }
      const ratios=['2:3','3:2','1:1','9:16','16:9'];
      const btns = document.querySelectorAll('button,[role="button"],div,span');
      for (const b of btns) {
        const s=window.getComputedStyle(b);
        if (s.display==='none'||s.visibility==='hidden') continue;
        const r=b.getBoundingClientRect();
        if (r.width<20||r.width>180||r.height<16||r.height>90) continue;
        const t=(b.innerText||'').replace(/\s+/g,'');
        if (ratios.some(ra=>t.includes(ra)) && r.bottom>window.innerHeight*0.72)
          return {x:Math.round(r.left+r.width/2),y:Math.round(r.top+r.height/2)};
      }
      return null;
    }

_JS_FIND_DURATION:
(target) => {
      const map={'6s':['6s','6 seconds'],'10s':['10s','10 seconds']};
      const vals=(map[target]||map['6s']).map(v=>v.toLowerCase());
      const els = document.querySelectorAll('span,button,[role="button"],div');
      for (const el of els) {
        const s = window.getComputedStyle(el);
        if (s.display==='none'||s.visibility==='hidden') continue;
        const r = el.getBoundingClientRect();
        if (r.width<10||r.height<10) continue;
        const t = (el.innerText||'').trim().toLowerCase().replace(/\s+/g,' ');
        if (!vals.some(v=>t===v)) continue;
        let pill=el, node=el.parentElement;
        for (let d=0;node&&d<4;d++){
          const pr=node.getBoundingClientRect();
          const pt=(node.innerText||'').replace(/\s/g,'').toLowerCase();
          if (['6s','10s'].filter(q=>pt.includes(q)).length<=1
              && pr.width>=24&&pr.width<=120&&pr.height>=20&&pr.height<=52) pill=node;
          node=node.parentElement;
        }
        const pr=pill.getBoundingClientRect();
        return {x:Math.round(pr.left+pr.width/2),y:Math.round(pr.top+pr.height/2)};
      }
      return null;
    }

