_JS_FIND_NEW_IMAGE:
(existing) => {
      // Grok Imagine renders the finished photo as an <img alt="Generated image">
      // whose src is a data: URI (base64) OR a CDN asset URL. Match both — BUT
      // skip the live preview: while generating, the same <img> holds a tiny
      // (~25KB) low-res data: URI that grows to the full image only when done.
      const ok=(u)=>{
        if(!u)return false;
        if(u.startsWith('data:image'))return true;
        if(!/^https?:/i.test(u))return false;
        if(/\.(xml|json|html?|txt)(\?|$)/i.test(u))return false;
        return /\.(png|jpe?g|webp|gif)(\?|$)/i.test(u)
          ||/\/(image|images)\//i.test(u)
          ||/[?&](format|type|mime)=image/i.test(u)
          ||/\/(generated|media|asset|cdn)\//i.test(u);
      };
      // "Finished": a CDN asset URL, OR a data: URI whose base64 payload is large
      // (>~112KB; the preview is ~25KB→~34k chars), OR a full-res rendered <img>.
      const ready=(el,u)=>{
        if(u.startsWith('data:')){const c=u.indexOf(',');return c>0&&(u.length-c)>150000;}
        return (el&&(el.naturalWidth||0)>=768);
      };
      // 1) Highest priority: the explicit generated-image element (newest first).
      const gen=Array.from(document.querySelectorAll('img[alt="Generated image"]')).reverse();
      for (const el of gen){
        const u=el.currentSrc||el.src||'';
        if (u&&!existing.includes(u)&&ready(el,u)) return u;
      }
      // 2) Any other new, finished image, newest first.
      const els=Array.from(document.querySelectorAll('img')).reverse();
      for (const el of els){
        const u=el.currentSrc||el.src||'';
        if (ok(u)&&!existing.includes(u)&&ready(el,u)) return u;
      }
      // 3) A finished CDN asset behind an <a> (always full-res; never a preview).
      const links=Array.from(document.querySelectorAll('a[href]')).reverse();
      for (const l of links){
        if (ok(l.href)&&!existing.includes(l.href)&&!l.href.startsWith('data:')) return l.href;
      }
      return null;
    }

_JS_FIND_NEW_VIDEO:
(existing) => {
      const els=document.querySelectorAll('video source,video');
      for (let i=els.length-1;i>=0;i--){
        const u=els[i].currentSrc||els[i].src||'';
        if (u&&u.startsWith('http')&&!existing.includes(u)) return u;
      }
      // Fallback: download/share anchor pointing at a video file (extension: findLatestMediaUrl)
      const isVid=(u)=>/\.(mp4|webm|mov)(\?|$)/i.test(u)||/\/(video|videos)\//i.test(u)||/[?&](format|type|mime)=video/i.test(u);
      const links=Array.from(document.querySelectorAll('a[href]'));
      for (let i=links.length-1;i>=0;i--){
        const u=links[i].href||'';
        if (u&&u.startsWith('http')&&isVid(u)&&!existing.includes(u)) return u;
      }
      return null;
    }

