_JS_SET_PROMPT:
(text) => {
      const sels = [
        "textarea[placeholder*='imagine' i]","textarea[placeholder*='message' i]",
        "textarea[placeholder*='prompt' i]","[contenteditable='true']",
        "[role='textbox']","textarea"];
      let input = null;
      for (const sel of sels) {
        const el = document.querySelector(sel);
        if (el && el.getBoundingClientRect().width > 0) { input = el; break; }
      }
      if (!input) return {ok:false, error:'textarea not found'};
      input.focus();
      if (input.matches('textarea,input')) {
        const desc = Object.getOwnPropertyDescriptor(input.constructor.prototype,'value');
        if (desc&&desc.set) desc.set.call(input, text);
        else input.value = text;
        input.dispatchEvent(new InputEvent('beforeinput',
          {bubbles:true,cancelable:true,inputType:'insertText',data:text}));
        input.dispatchEvent(new InputEvent('input',
          {bubbles:true,inputType:'insertText',data:text}));
        input.dispatchEvent(new Event('change',{bubbles:true}));
      } else {
        input.textContent = text;
        input.dispatchEvent(new InputEvent('input',
          {bubbles:true,inputType:'insertText',data:text}));
      }
      return {ok:true};
    }
